#include<bits/stdc++.h>
#define rep(a,b,c) for(register int c=(a);c<=(b);++c)
#define drep(a,b,c) for(register int c=(a);c>=(b);--c)
#define int long long
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
const int M=5e6+10,LIM=5e6;int Mod,Inv2,Inv6;
int mu[M],pm[M>>2],cpt;bool vs[M];long long ph[M];int N;
inline void Init(int mx=LIM)
{
	vs[1]=1;ph[1]=1;rep(2,mx,i)
	{
		vs[i]?0:(pm[++cpt]=i,mu[i]=-1,ph[i]=i-1);
		for(register int j=1;j<=cpt&&i*pm[j]<=mx;++j)
			{vs[pm[j]*i]=1;if(i%pm[j]==0){ph[i*pm[j]]=ph[i]*pm[j];break;}ph[pm[j]*i]=ph[i]*(pm[j]-1);}
	}
	rep(1,mx,i)ph[i]=(ph[i-1]+1ll*ph[i]*i%Mod*i%Mod)%Mod;
}
inline int qpow(int a,int b=Mod-2)
{
	int res=1;while(b)
	{
		if(b&1)res=1ll*res*a%Mod;
		a=1ll*a*a%Mod;b=b>>1;
	}return res;
}
inline int Ssm(int x){x%=Mod;return 1ll*x*(x+1)%Mod*Inv2%Mod;}
inline int Ssq(int x){x%=Mod;return 1ll*x*(x+1)%Mod*(2*x+1)%Mod*Inv6%Mod;}
int sum[M];
inline int Qry(int n,int d=1)
{
    if(n<=LIM)return ph[n];if(sum[d])return sum[d];
    int res=Ssm(n)*Ssm(n)%Mod;
    for(register long long l=2,r;l<=n;l=r+1)
    {
        r=n/(n/l);
//        puts("tmdzz");
        int tt=(Ssq(r)-Ssq(l-1)+Mod)%Mod;
		res=(res-Qry(n/l,d*l)*tt%Mod+Mod)%Mod;
    }
    return sum[d]=res;
}
signed main()
{
	Mod=read();N=read();Init();Inv2=qpow(2);Inv6=qpow(6);
	long long ans=0;for(register long long l=1,r;l<=N;l=r+1)
	{
		r=N/(N/l);
		ans=(ans+1ll*Ssm(N/l)*Ssm(N/l)%Mod*(Qry(r)-Qry(l-1)+Mod)%Mod)%Mod;
	}
	printf("%lld\n",ans);
}
